class Solution:
    def longestConsecutive(self, nums: List[int]) -> int:
        s = set(nums)
        best = 0
        for n in s:
            if n - 1 not in s:
                cur, length = n, 0
                while cur in s:
                    length += 1
                    cur += 1
                best = max(best, length)
        return best

